import type { Badge } from "../../componentTypes/badge"
import type { Semantics } from "../semantics"

const badge = (semantics: Semantics): Badge => ({
  borderRadius: semantics.borderRadius.full,
  fontFamily: semantics.fontFamily.base,
  color: semantics.color.text.onColor,
  colorInverse: semantics.color.text.dark,
  colorDanger: semantics.color.background.error,
  colorSuccess: semantics.color.background.success,
  colorPrimary: semantics.color.background.info,
  fontSize: semantics.fontSize.textSm,
  fontWeight: semantics.fontWeight.body.strong,
  sizeNotification: "0.75rem",
  size: "1.25rem",
  padding: semantics.spacing.spaceXs,
  notificationOffset: "0.125rem",
  notificationZIndex: 1,
  pulseBorderThickness: "0.125rem",
  countOffset: "0.5rem",
})
export default badge
